// 1. Pegamos o corpo (HTML) que está entrando neste nó
const html = $json.data || "";

// 2. Pegamos os headers do nó anterior usando a sintaxe mais moderna ($('Nome').item)
// Certifique-se que o nome do nó anterior é exatamente "GET Login Page"
let setCookie = "";
try {
  const headers = $('GET Login Page').item.json.headers;
  const cookieHeader = headers['set-cookie'];

  if (Array.isArray(cookieHeader)) {
    setCookie = cookieHeader[0].split(';')[0];
  } else if (typeof cookieHeader === 'string') {
    setCookie = cookieHeader.split(';')[0];
  }
} catch (e) {
  setCookie = ""; // Caso não encontre o cookie, evita que o nó trave
}

// 3. Extração do Token com um Regex mais flexível
// (Tenta pegar o value independente da ordem dos atributos)
const tokenMatch = html.match(/name="__RequestVerificationToken".*?value="([^"]+)"/) 
                || html.match(/value="([^"]+)".*?name="__RequestVerificationToken"/);

return [{
  token: tokenMatch ? tokenMatch[1] : null,
  cookie: setCookie,
  // Debug: se o token vier null, você verá o HTML aqui para conferir
  htmlLength: html.length 
}];

// 1. Pegamos os novos Cookies que o 'POST Login' gerou
const loginNode = $('POST Login').item.json;
const setCookies = loginNode.headers['set-cookie'] || [];
const sessionCookies = setCookies.map(c => c.split(';')[0]).join('; ');

// 2. Pegamos o Token e o Cookie inicial do nó de extração anterior
// Certifique-se que o nome do nó de extração é exatamente este:
const extracaoAnterior = $('Extrair Token e Cookie').item.json;
const token = extracaoAnterior.token;
const cookieInicial = extracaoAnterior.cookie;

// 3. Juntamos tudo em uma única string de cookie
const allCookies = [cookieInicial, sessionCookies].filter(Boolean).join('; ');

return [{
  token: token,
  allCookies: allCookies
}];

const html = $json.data;
const results = [];

// 1. Localiza o corpo da tabela
const tableMatch = html.match(/<table[^>]*>([\s\S]*?)<\/table>/);
if (!tableMatch) return [{ aviso: "Nenhuma tabela encontrada" }];

// 2. Quebra o HTML em linhas (tr)
const rows = tableMatch[1].match(/<tr>([\s\S]*?)<\/tr>/g) || [];

for (const row of rows) {
    // Busca o Nome (dentro da classe text-item__title)
    const nomeMatch = row.match(/class="text-item__title">([^<]+)<\/p>/);
    if (!nomeMatch) continue; // Pula se não encontrar nome (cabeçalho, etc)

    // Busca o Documento (limpando o texto "Documento:")
    const docMatch = row.match(/<strong>Documento: <\/strong>\s*([^<]+)<\/p>/);

    // Busca a Localidade (Cidade/Estado)
    const localMatch = row.match(/<span class="text-item__detail">([^<]+)<\/span>/g);
    // No seu HTML, a localidade é o segundo span de detalhe encontrado no bloco
    let localidade = "";
    if (localMatch && localMatch.length > 1) {
        localidade = localMatch[localMatch.length - 1].replace(/<[^>]+>/g, '').replace(/&nbsp;/g, '').trim();
    }

    // Busca o ID de consulta detalhada (aquela string que começa com !)
    const idMatch = row.match(/pesquisaCPFCNPJ\('([^']+)'/);

    results.push({
        nome: nomeMatch[1].trim(),
        documento: docMatch ? docMatch[1].trim() : null,
        localidade: localidade,
        id_detalhes: idMatch ? idMatch[1] : null
    });
}

return results;
